import sys, ast
sys.path.insert(0, '.')

results = {}
for phase_num in range(1, 6):
    phase_dirs = {
        1: 'phase1_data_quality',
        2: 'phase2_feature_engineering',
        3: 'phase3_model_tuning',
        4: 'phase4_validation',
        5: 'phase5_postprocessing',
    }
    d = phase_dirs[phase_num]
    # Parse __init__.py to get imported names
    init_path = f'ml_framework/{d}/__init__.py'
    try:
        tree = ast.parse(open(init_path).read())
    except:
        print(f'Phase {phase_num}: could not parse __init__.py')
        continue

    imported_names = set()
    for node in ast.walk(tree):
        if isinstance(node, ast.ImportFrom):
            for alias in node.names:
                imported_names.add(alias.asname or alias.name)

    # Try importing each name
    failed = []
    for name in sorted(imported_names):
        try:
            mod = __import__(f'ml_framework.{d}', fromlist=[name])
            getattr(mod, name)
        except (AttributeError, ImportError) as e:
            failed.append(f'{name}: {e}')

    if failed:
        print(f'Phase {phase_num}: {len(failed)} FAILED')
        for f in failed:
            print(f'  - {f}')
    else:
        print(f'Phase {phase_num}: All {len(imported_names)} names OK')

